import React, { useRef, useMemo, useEffect } from 'react';
import { Canvas, useFrame, useThree } from '@react-three/fiber';
import { OrbitControls, Float, Text3D, Center } from '@react-three/drei';
import * as THREE from 'three';

// Floating geometric shapes
function FloatingShapes() {
  const shapes = useMemo(() => {
    return Array.from({ length: 15 }, (_, i) => ({
      id: i,
      position: [
        (Math.random() - 0.5) * 20,
        (Math.random() - 0.5) * 10,
        (Math.random() - 0.5) * 10
      ],
      rotation: [Math.random() * Math.PI, Math.random() * Math.PI, Math.random() * Math.PI],
      scale: Math.random() * 0.5 + 0.2,
      type: ['box', 'sphere', 'torus', 'cone', 'octahedron'][Math.floor(Math.random() * 5)]
    }));
  }, []);

  return (
    <>
      {shapes.map((shape) => (
        <Float
          key={shape.id}
          speed={Math.random() * 2 + 1}
          rotationIntensity={Math.random() * 0.5 + 0.5}
          floatIntensity={Math.random() * 2 + 1}
        >
          <mesh
            position={shape.position}
            rotation={shape.rotation}
            scale={shape.scale}
          >
            {shape.type === 'box' && <boxGeometry args={[1, 1, 1]} />}
            {shape.type === 'sphere' && <sphereGeometry args={[0.7, 32, 32]} />}
            {shape.type === 'torus' && <torusGeometry args={[0.7, 0.3, 16, 32]} />}
            {shape.type === 'cone' && <coneGeometry args={[0.7, 1.5, 32]} />}
            {shape.type === 'octahedron' && <octahedronGeometry args={[0.7]} />}

            <meshStandardMaterial
              color={shape.id % 3 === 0 ? '#3B82F6' : shape.id % 3 === 1 ? '#e50914' : '#1F2937'}
              metalness={0.8}
              roughness={0.2}
              emissive={shape.id % 3 === 0 ? '#3B82F6' : shape.id % 3 === 1 ? '#e50914' : '#1F2937'}
              emissiveIntensity={0.1}
            />
          </mesh>
        </Float>
      ))}
    </>
  );
}

// Particle system
function Particles() {
  const particles = useMemo(() => {
    return Array.from({ length: 100 }, (_, i) => ({
      position: [
        (Math.random() - 0.5) * 30,
        (Math.random() - 0.5) * 20,
        (Math.random() - 0.5) * 20
      ],
      speed: Math.random() * 0.02 + 0.01
    }));
  }, []);

  useFrame((state) => {
    particles.forEach((particle, i) => {
      particle.position[1] += particle.speed;
      if (particle.position[1] > 10) {
        particle.position[1] = -10;
      }
    });
  });

  return (
    <points>
      <bufferGeometry>
        <bufferAttribute
          attach="attributes-position"
          count={particles.length}
          array={new Float32Array(particles.flatMap(p => p.position))}
          itemSize={3}
        />
      </bufferGeometry>
      <pointsMaterial
        color="#3B82F6"
        size={0.05}
        transparent
        opacity={0.6}
      />
    </points>
  );
}

// Mouse interaction
function MouseFollower() {
  const { camera, mouse } = useThree();
  const ref = useRef();

  useFrame((state) => {
    if (ref.current) {
      ref.current.position.x = mouse.x * 2;
      ref.current.position.y = mouse.y * 2;
    }
  });

  return (
    <mesh ref={ref}>
      <sphereGeometry args={[0.1, 32, 32]} />
      <meshBasicMaterial color="#e50914" />
    </mesh>
  );
}

// Main 3D Scene
function Scene() {
  return (
    <>
      <ambientLight intensity={0.3} />
      <directionalLight position={[10, 10, 5]} intensity={1} color="#ffffff" />
      <pointLight position={[-10, -10, -5]} intensity={0.5} color="#3B82F6" />
      <pointLight position={[10, -10, 5]} intensity={0.5} color="#e50914" />

      <FloatingShapes />
      <Particles />
      <MouseFollower />
    </>
  );
}

export default function ThreeBackground() {
  return (
    <div className="absolute inset-0 z-0">
      <Canvas
        camera={{ position: [0, 0, 10], fov: 75 }}
        style={{ background: 'transparent' }}
      >
        <Scene />
      </Canvas>
    </div>
  );
}
